#include <bits/stdc++.h>
using namespace std; 
int fail=-1,now=0,ans; 
int n;
bool a; 
int main(){
	cin>>n;
	while(n--){
		cin>>a;
		if(a==0){ 
			fail++;
			continue;
		}
		else{
			if(fail>=0){ 
				now-=pow(2,fail);
				fail=-1; 
			}
			if(now<0)now=0;
			now++;
			ans++; 
			if(now>=3)ans++;
			if(now>=7)ans++;
			if(now>=30)ans++;
			if(now>=120)ans++;
			if(now>=365)ans++;
		}
	}
	cout<<ans<<endl;
	return 0;
}
